SELECT AVG(t.capacity) AS average_capacity
FROM seasons s
JOIN teams t ON s.winner = t.team_id;

SELECT AVG(capacity) 
FROM teams 
WHERE conference = (SELECT conference FROM teams WHERE team_name = 'Atlanta Hawks');

SELECT COUNT(season_id) 
FROM seasons 
WHERE winner = (SELECT team_id FROM teams WHERE team_name = 'Boston Celtics');

SELECT COUNT(DISTINCT user_id) AS total_users
FROM user_access
WHERE access_date LIKE '2023-%' AND access_type = 'view';

SELECT season_id
FROM seasons
WHERE winner IN (SELECT team_id FROM teams WHERE conference = 'Eastern');
